import{_ as e,c as o,o as d,ag as r}from"./chunks/framework.Bw-5EFTY.js";const u=JSON.parse('{"title":"dag-orchestrator SPEC.md","description":"","frontmatter":{},"headers":[],"relativePath":"packages/dag-orchestrator/SPEC.md","filePath":"packages/dag-orchestrator/SPEC.md"}'),a={name:"packages/dag-orchestrator/SPEC.md"};function s(c,t,i,n,p,l){return d(),o("div",null,t[0]||(t[0]=[r(`<h1 id="dag-orchestrator-spec-md" tabindex="-1">dag-orchestrator SPEC.md <a class="header-anchor" href="#dag-orchestrator-spec-md" aria-label="Permalink to &quot;dag-orchestrator SPEC.md&quot;">​</a></h1><h2 id="scope" tabindex="-1">Scope <a class="header-anchor" href="#scope" aria-label="Permalink to &quot;Scope&quot;">​</a></h2><p><code>@robota-sdk/dag-orchestrator</code> is the orchestration layer that bridges DAG definitions to Prompt API (ComfyUI-compatible) execution. It owns the translation of <code>IDagDefinition</code> into <code>IPromptRequest</code>, run lifecycle management (create, start, poll, result), cost estimation gating, and HTTP communication with a Prompt API server. This package is backend-agnostic: it works against both the Robota <code>dag-runtime-server</code> and a native ComfyUI server through the <code>IPromptApiClientPort</code> abstraction.</p><h2 id="boundaries" tabindex="-1">Boundaries <a class="header-anchor" href="#boundaries" aria-label="Permalink to &quot;Boundaries&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Responsibility</th><th>Owner</th><th>NOT this package</th></tr></thead><tbody><tr><td>DAG domain types (<code>IDagDefinition</code>, <code>IPromptRequest</code>, <code>TResult</code>, <code>IDagError</code>, <code>IRunResult</code>)</td><td><code>@robota-sdk/dag-core</code></td><td>Imported, not owned</td></tr><tr><td>Runtime execution (node execution, asset storage, queue processing)</td><td><code>dag-runtime-server</code></td><td>Not touched</td></tr><tr><td>HTTP server routing, request handling, SSE/WebSocket events</td><td><code>dag-orchestrator-server</code></td><td>Consumer of this package</td></tr><tr><td>DAG storage and persistence</td><td><code>dag-orchestrator-server</code> (in-memory or external)</td><td>Not owned</td></tr><tr><td>UI and designer interactions</td><td><code>dag-designer</code>, <code>web</code> app</td><td>Not owned</td></tr><tr><td>Node definitions and catalog</td><td><code>dag-core</code>, <code>dag-nodes-*</code></td><td>Not owned</td></tr></tbody></table><h2 id="architecture-overview" tabindex="-1">Architecture Overview <a class="header-anchor" href="#architecture-overview" aria-label="Permalink to &quot;Architecture Overview&quot;">​</a></h2><p>The package follows a <strong>ports-and-adapters</strong> architecture with two service layers:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>index.ts (public surface)</span></span>
<span class="line"><span>  |</span></span>
<span class="line"><span>  +-- services/</span></span>
<span class="line"><span>  |     +-- OrchestratorRunService      (run lifecycle: create, start, poll, result)</span></span>
<span class="line"><span>  |     +-- PromptOrchestratorService   (prompt submission with cost policy gating)</span></span>
<span class="line"><span>  |</span></span>
<span class="line"><span>  +-- adapters/</span></span>
<span class="line"><span>  |     +-- HttpPromptApiClient         (IPromptApiClientPort -&gt; HTTP fetch)</span></span>
<span class="line"><span>  |     +-- translateDefinitionToPrompt (IDagDefinition -&gt; IPromptRequest pure function)</span></span>
<span class="line"><span>  |</span></span>
<span class="line"><span>  +-- interfaces/</span></span>
<span class="line"><span>  |     +-- IPromptApiClientPort        (port to Prompt API server)</span></span>
<span class="line"><span>  |     +-- ICostEstimatorPort          (port for cost estimation)</span></span>
<span class="line"><span>  |     +-- ICostPolicyEvaluatorPort    (port for cost policy evaluation)</span></span>
<span class="line"><span>  |</span></span>
<span class="line"><span>  +-- types/</span></span>
<span class="line"><span>        +-- orchestrator-types.ts       (SSOT types for orchestration config)</span></span></code></pre></div><p><strong>Key design decisions:</strong></p><ul><li>All public methods return <code>TResult&lt;T, IDagError&gt;</code>. No exceptions are thrown for domain failures.</li><li><code>OrchestratorRunService</code> manages run state in-memory via a <code>Map&lt;string, IRunState&gt;</code>. It is stateful and scoped to the server process lifetime.</li><li><code>PromptOrchestratorService</code> is stateless; each call delegates to the injected ports.</li><li><code>translateDefinitionToPrompt</code> is a pure function (no side effects, no I/O).</li></ul><h2 id="type-ownership" tabindex="-1">Type Ownership <a class="header-anchor" href="#type-ownership" aria-label="Permalink to &quot;Type Ownership&quot;">​</a></h2><p>Types <strong>owned</strong> by this package (SSOT):</p><table tabindex="0"><thead><tr><th>Type</th><th>Location</th><th>Purpose</th></tr></thead><tbody><tr><td><code>IPromptCostEstimate</code></td><td><code>types/orchestrator-types.ts</code></td><td>Per-prompt cost estimation result (<code>totalEstimatedCredits</code>, <code>perNode</code> with <code>estimatedCredits</code>)</td></tr><tr><td><code>IPromptCostPolicy</code></td><td><code>types/orchestrator-types.ts</code></td><td>Max cost threshold configuration (<code>maxCreditsPerPrompt</code>)</td></tr><tr><td><code>IRetryPolicy</code></td><td><code>types/orchestrator-types.ts</code></td><td>Retry configuration (max retries, backoff, retryable error codes)</td></tr><tr><td><code>ITimeoutPolicy</code></td><td><code>types/orchestrator-types.ts</code></td><td>Prompt timeout configuration</td></tr><tr><td><code>IOrchestratorConfig</code></td><td><code>types/orchestrator-types.ts</code></td><td>Combined orchestrator configuration (cost + retry + timeout policies)</td></tr><tr><td><code>IOrchestratedPromptRequest</code></td><td><code>types/orchestrator-types.ts</code></td><td>Prompt request bundled with orchestrator config</td></tr><tr><td><code>IOrchestratedPromptResponse</code></td><td><code>types/orchestrator-types.ts</code></td><td>Prompt response bundled with optional cost estimate</td></tr><tr><td><code>IPromptApiClientPort</code></td><td><code>interfaces/prompt-api-client-port.ts</code></td><td>Port interface for Prompt API server communication</td></tr><tr><td><code>ICostEstimatorPort</code></td><td><code>interfaces/orchestrator-policy-port.ts</code></td><td>Port interface for cost estimation</td></tr><tr><td><code>ICostPolicyEvaluatorPort</code></td><td><code>interfaces/orchestrator-policy-port.ts</code></td><td>Port interface for cost policy evaluation</td></tr></tbody></table><p>Types <strong>imported</strong> from <code>@robota-sdk/dag-core</code> (not owned here):</p><p><code>IDagDefinition</code>, <code>IDagError</code>, <code>IPromptRequest</code>, <code>IPromptResponse</code>, <code>IQueueStatus</code>, <code>IQueueAction</code>, <code>THistory</code>, <code>TObjectInfo</code>, <code>ISystemStats</code>, <code>TResult</code>, <code>TPortPayload</code>, <code>IRunResult</code>, <code>IRunNodeTrace</code>, <code>IRunNodeError</code>, <code>TRunProgressEvent</code>, <code>TPromptInputValue</code>, <code>TPrompt</code>, <code>IDagEdgeDefinition</code></p><h2 id="public-api-surface" tabindex="-1">Public API Surface <a class="header-anchor" href="#public-api-surface" aria-label="Permalink to &quot;Public API Surface&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Export</th><th>Kind</th><th>Description</th></tr></thead><tbody><tr><td><code>PromptOrchestratorService</code></td><td>class</td><td>Stateless orchestrator: submits prompts with optional cost policy gating, delegates queue/history/objectInfo/systemStats to API client</td></tr><tr><td><code>OrchestratorRunService</code></td><td>class</td><td>Stateful run lifecycle manager: createRun, startRun, createAndStartRun, getRunStatus, getRunResult, recordEvent</td></tr><tr><td><code>HttpPromptApiClient</code></td><td>class</td><td>HTTP adapter implementing <code>IPromptApiClientPort</code> via <code>fetch()</code></td></tr><tr><td><code>translateDefinitionToPrompt</code></td><td>function</td><td>Pure translator: <code>IDagDefinition</code> + <code>TPortPayload</code> -&gt; <code>IPromptRequest</code></td></tr><tr><td><code>IPromptApiClientPort</code></td><td>interface (type export)</td><td>Port for Prompt API server communication</td></tr><tr><td><code>ICostEstimatorPort</code></td><td>interface (type export)</td><td>Port for cost estimation logic</td></tr><tr><td><code>ICostPolicyEvaluatorPort</code></td><td>interface (type export)</td><td>Port for cost policy evaluation logic</td></tr><tr><td><code>IPromptCostEstimate</code></td><td>interface (type export)</td><td>Cost estimation result shape</td></tr><tr><td><code>IPromptCostPolicy</code></td><td>interface (type export)</td><td>Cost policy configuration shape</td></tr><tr><td><code>IRetryPolicy</code></td><td>interface (type export)</td><td>Retry policy configuration shape</td></tr><tr><td><code>ITimeoutPolicy</code></td><td>interface (type export)</td><td>Timeout policy configuration shape</td></tr><tr><td><code>IOrchestratorConfig</code></td><td>interface (type export)</td><td>Combined orchestrator configuration</td></tr><tr><td><code>IOrchestratedPromptRequest</code></td><td>interface (type export)</td><td>Request bundled with config</td></tr><tr><td><code>IOrchestratedPromptResponse</code></td><td>interface (type export)</td><td>Response bundled with cost estimate</td></tr><tr><td><code>CelCostEstimatorAdapter</code></td><td>class</td><td><code>ICostEstimatorPort</code> adapter using CEL-based cost formulas from <code>@robota-sdk/dag-cost</code></td></tr></tbody></table><h2 id="extension-points" tabindex="-1">Extension Points <a class="header-anchor" href="#extension-points" aria-label="Permalink to &quot;Extension Points&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Port</th><th>Purpose</th><th>Implementors</th></tr></thead><tbody><tr><td><code>IPromptApiClientPort</code></td><td>Communicate with a Prompt API server (ComfyUI or Robota runtime)</td><td><code>HttpPromptApiClient</code> (built-in), in-memory stubs (tests)</td></tr><tr><td><code>ICostEstimatorPort</code></td><td>Estimate execution cost given <code>TPrompt</code> and <code>TObjectInfo</code></td><td><code>CelCostEstimatorAdapter</code> (built-in), consumer-provided</td></tr><tr><td><code>ICostPolicyEvaluatorPort</code></td><td>Evaluate whether an estimated cost passes a policy threshold</td><td>Consumer-provided; no built-in implementation</td></tr></tbody></table><p>All three ports are injected via constructor DI. Consumers can provide custom implementations without modifying this package.</p><h2 id="error-taxonomy" tabindex="-1">Error Taxonomy <a class="header-anchor" href="#error-taxonomy" aria-label="Permalink to &quot;Error Taxonomy&quot;">​</a></h2><p>All errors use <code>IDagError</code> from <code>@robota-sdk/dag-core</code> with <code>TResult&lt;T, IDagError&gt;</code> return types.</p><table tabindex="0"><thead><tr><th>Code</th><th>Category</th><th>Retryable</th><th>Source</th><th>Description</th></tr></thead><tbody><tr><td><code>ORCHESTRATOR_EMPTY_DEFINITION</code></td><td><code>validation</code></td><td>No</td><td><code>translateDefinitionToPrompt</code></td><td>Definition has zero nodes</td></tr><tr><td><code>ORCHESTRATOR_RUN_NOT_FOUND</code></td><td><code>validation</code></td><td>No</td><td><code>OrchestratorRunService</code></td><td>dagRunId does not exist in the run map</td></tr><tr><td><code>ORCHESTRATOR_RUN_ALREADY_STARTED</code></td><td><code>validation</code></td><td>No</td><td><code>OrchestratorRunService.startRun</code></td><td>Attempted to start a run that is not in <code>pending</code> status</td></tr><tr><td><code>ORCHESTRATOR_RUN_NOT_COMPLETED</code></td><td><code>validation</code></td><td>No</td><td><code>OrchestratorRunService.getRunResult</code></td><td>Run has not been started or has not completed yet</td></tr><tr><td><code>NETWORK_ERROR</code></td><td><code>dispatch</code></td><td>Yes</td><td><code>HttpPromptApiClient</code></td><td>Failed to connect to Prompt API server</td></tr><tr><td><code>HTTP_&lt;status&gt;</code></td><td><code>validation</code></td><td>Yes (5xx) / No (4xx)</td><td><code>HttpPromptApiClient</code></td><td>Non-OK HTTP response from Prompt API server</td></tr><tr><td><code>COST_LIMIT_EXCEEDED</code></td><td><code>validation</code></td><td>No</td><td>Consumer-provided <code>ICostPolicyEvaluatorPort</code></td><td>Cost estimate exceeds policy threshold</td></tr></tbody></table><h2 id="test-strategy" tabindex="-1">Test Strategy <a class="header-anchor" href="#test-strategy" aria-label="Permalink to &quot;Test Strategy&quot;">​</a></h2><h3 id="current-test-files" tabindex="-1">Current test files <a class="header-anchor" href="#current-test-files" aria-label="Permalink to &quot;Current test files&quot;">​</a></h3><table tabindex="0"><thead><tr><th>File</th><th>Type</th><th>Coverage</th></tr></thead><tbody><tr><td><code>prompt-orchestrator-service.test.ts</code></td><td>Unit</td><td>Submits with/without cost policy, cost rejection, delegation of getQueue/getHistory/getSystemStats</td></tr><tr><td><code>prompt-api-client-port.test.ts</code></td><td>Contract</td><td>Verifies <code>IPromptApiClientPort</code> is implementable as an in-memory stub</td></tr><tr><td><code>backend-interchangeability.test.ts</code></td><td>Contract (integration-style)</td><td>Proves <code>HttpPromptApiClient</code> works identically against mock Robota and ComfyUI servers; cross-backend response shape parity</td></tr><tr><td><code>translator-contract.test.ts</code></td><td>Contract</td><td>Validates <code>translateDefinitionToPrompt</code>: primitive/object/array config, edge bindings, slot indices, input node, class_type, _meta, empty definition error</td></tr><tr><td><code>run-service-contract.test.ts</code></td><td>Contract</td><td>Validates <code>OrchestratorRunService</code>: createRun/startRun lifecycle, dagRunId=promptId, recordEvent accumulation, getRunStatus/getRunResult shapes, dual-index lookup</td></tr></tbody></table><h3 id="coverage-gaps" tabindex="-1">Coverage gaps <a class="header-anchor" href="#coverage-gaps" aria-label="Permalink to &quot;Coverage gaps&quot;">​</a></h3><ul><li><strong>Retry and timeout policies</strong>: <code>IRetryPolicy</code> and <code>ITimeoutPolicy</code> are defined in types but not implemented in any service. No tests exist for these paths.</li></ul><h3 id="verification-commands" tabindex="-1">Verification commands <a class="header-anchor" href="#verification-commands" aria-label="Permalink to &quot;Verification commands&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --filter</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> @robota-sdk/dag-orchestrator</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> test</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --filter</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> @robota-sdk/dag-orchestrator</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build</span></span></code></pre></div><h2 id="class-contract-registry" tabindex="-1">Class Contract Registry <a class="header-anchor" href="#class-contract-registry" aria-label="Permalink to &quot;Class Contract Registry&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Class / Function</th><th>Implements / Extends</th><th>Port Consumer</th></tr></thead><tbody><tr><td><code>HttpPromptApiClient</code></td><td>implements <code>IPromptApiClientPort</code></td><td>--</td></tr><tr><td><code>CelCostEstimatorAdapter</code></td><td>implements <code>ICostEstimatorPort</code></td><td>Injects <code>ICostMetaStoragePort</code> from <code>@robota-sdk/dag-cost</code></td></tr><tr><td><code>PromptOrchestratorService</code></td><td>--</td><td>Injects <code>IPromptApiClientPort</code>, <code>ICostEstimatorPort</code>, <code>ICostPolicyEvaluatorPort</code></td></tr><tr><td><code>OrchestratorRunService</code></td><td>--</td><td>Injects <code>IPromptApiClientPort</code></td></tr><tr><td><code>translateDefinitionToPrompt</code></td><td>pure function (no port)</td><td>--</td></tr></tbody></table><h3 id="cross-package-consumers" tabindex="-1">Cross-package consumers <a class="header-anchor" href="#cross-package-consumers" aria-label="Permalink to &quot;Cross-package consumers&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Consumer (external)</th><th>Port consumed</th><th>Package</th></tr></thead><tbody><tr><td><code>dag-orchestrator-server</code> routes</td><td><code>OrchestratorRunService</code>, <code>PromptOrchestratorService</code></td><td><code>apps/dag-orchestrator-server</code></td></tr></tbody></table><h2 id="dependencies" tabindex="-1">Dependencies <a class="header-anchor" href="#dependencies" aria-label="Permalink to &quot;Dependencies&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Dependency</th><th>Kind</th><th>Purpose</th></tr></thead><tbody><tr><td><code>@robota-sdk/dag-core</code></td><td>production</td><td>Domain types (<code>IDagDefinition</code>, <code>IPromptRequest</code>, <code>TResult</code>, <code>IDagError</code>, etc.)</td></tr><tr><td><code>@robota-sdk/dag-cost</code></td><td>production</td><td>Cost meta types and CEL evaluator (<code>ICostMetaStoragePort</code>, <code>CelCostEvaluator</code>)</td></tr><tr><td><code>express</code></td><td>dev</td><td>Mock server for backend interchangeability tests</td></tr><tr><td><code>vitest</code></td><td>dev</td><td>Test runner</td></tr><tr><td><code>tsup</code></td><td>dev</td><td>Build tool</td></tr></tbody></table>`,36)]))}const m=e(a,[["render",s]]);export{u as __pageData,m as default};
